static int
ctrl_add( void )
{
	LDAPControl	*tmpc;

	nctrls++;
	tmpc = realloc( c, sizeof( LDAPControl ) * nctrls );
	if ( tmpc == NULL ) {
		nctrls--;
		fprintf( stderr,
			_("unable to make room for control; out of memory?\n"));
		return -1;
	}
	c = tmpc;

	return 0;
}

static void
urlize(char *url)
{
	char *p;

	if (*LDAP_DIRSEP != '/') {
		for (p = url; *p; p++) {
			if (*p == *LDAP_DIRSEP)
				*p = '/';
		}
	}
}

static int
parse_vlv(char *cvalue)
{
	char *keyp, *key2;
	int num1, num2;

	keyp = cvalue;
	if ( sscanf( keyp, "%d/%d", &num1, &num2 ) != 2 ) {
		fprintf( stderr,
			_("VLV control value \"%s\" invalid\n"),
			cvalue );
		return -1;
	}
	vlvInfo.ldvlv_before_count = num1;
	vlvInfo.ldvlv_after_count = num2;
	keyp = strchr( keyp, '/' ) + 1;
	key2 = strchr( keyp, '/' );
	if ( key2 ) {
		keyp = key2 + 1;
		if ( sscanf( keyp, "%d/%d", &num1, &num2 ) != 2 ) {
			fprintf( stderr,
				_("VLV control value \"%s\" invalid\n"),
				cvalue );
			return -1;
		}
		vlvInfo.ldvlv_offset = num1;
		vlvInfo.ldvlv_count = num2;
		vlvInfo.ldvlv_attrvalue = NULL;
	} else {
		key2 = strchr( keyp, ':' );
		if ( !key2 ) {
			fprintf( stderr,
				_("VLV control value \"%s\" invalid\n"),
				cvalue );
			return -1;
		}
		ber_str2bv( key2+1, 0, 0, &vlvValue );
		vlvInfo.ldvlv_attrvalue = &vlvValue;
	}
	return 0;
}

